// Base64-encoded Noto Sans TTF, subset to Latin + Cyrillic + combining
// diacritics + basic punctuation (no CJK, no emoji/symbols, no extended or
// historic scripts). Used to embed real, selectable Cyrillic text into the
// PDF via doc.addFileToVFS() + doc.addFont() in generatePdf.ts — jsPDF's
// built-in fonts (Helvetica/Times/Courier) have no Cyrillic glyphs at all.
//
// jsPDF has its own hand-rolled TTF parser (not a real font library) and is
// picky about subsetted fonts: aggressive fontTools flags like
// --glyph-names, --name-IDs='', --drop-tables, --symbol-cmap etc. produced
// a font it silently failed to parse (threw inside doc.text()). Only
// --no-hinting and --layout-features='' survived testing against the
// installed jsPDF version (4.2.1) — do not add more aggressive subsetting
// flags without re-testing an actual doc.text() call with Cyrillic input.
//
// Regenerate with (from a clean checkout, requires Python + fonttools):
//
//   pip install fonttools brotli
//   curl -s -H "User-Agent: Mozilla/5.0 (Windows NT 5.1) AppleWebKit/535.1 (KHTML, like Gecko) Chrome/13.0.782.0 Safari/535.1" //     "https://fonts.googleapis.com/css2?family=Noto+Sans:wght@400;700&display=swap&subset=cyrillic,cyrillic-ext,latin,latin-ext" //     > notosans.css   # old Chrome UA -> Google Fonts serves WOFF1, not WOFF2
//   # extract the two src url(...) links from notosans.css and curl them to
//   # notosans-400.woff / notosans-700.woff, then:
//   python -c "from fontTools.ttLib import TTFont; //     f = TTFont('notosans-400.woff'); f.flavor = None; f.save('notosans-400.ttf')"
//   python -c "from fontTools.ttLib import TTFont; //     f = TTFont('notosans-700.woff'); f.flavor = None; f.save('notosans-700.ttf')"
//   python -m fontTools.subset notosans-400.ttf //     --unicodes="U+0000-00FF,U+0100-017F,U+0300-036F,U+0400-04FF,U+2010-2027,U+20AC" //     --no-hinting --layout-features='' --output-file=notosans-400-subset.ttf
//   python -m fontTools.subset notosans-700.ttf //     --unicodes="U+0000-00FF,U+0100-017F,U+0300-036F,U+0400-04FF,U+2010-2027,U+20AC" //     --no-hinting --layout-features='' --output-file=notosans-700-subset.ttf
//   # then base64-encode each *-subset.ttf and paste in below.
//
// Unicode ranges covered: Basic Latin + Latin-1 Supplement, Latin Extended-A
// (Czech diacritics: c-haček, s-haček, z-haček, r-haček, u-kroužek, etc.),
// combining diacritical marks (the pronunciation guide's stress-accent
// marks), Cyrillic (covers Russian and Ukrainian, including the
// Ukrainian-specific letters gie, ye, i, yi), and a small general-punctuation
// range (dashes, quotes, ellipsis). No emoji/symbol glyphs: Noto Sans (the
// text family) does not contain any 🌀-range or dingbat glyphs at
// all, at any subset size, so the category emoji used on the web page are
// dropped in the PDF rather than rendering as invisible/tofu glyphs.

export const NOTO_SANS_REGULAR_BASE64 =
  "";

export const NOTO_SANS_BOLD_BASE64 =
  "";
